<script setup lang="ts">import ServiceIcon from'./ServiceIcon.vue';import StatusBadge from'./StatusBadge.vue';defineProps<{visit:{registerId?:number;status:string;department:string;doctor:string;date:string;time:string;location?:string;patient?:string;previsitState?:'none'|'in_progress'|'completed'}}>();defineEmits<{action:[];previsit:[]}>()</script>
<template><view class="visit-card card"><view class="card-head"><StatusBadge :status="visit.status"/><text class="order-no">挂号单号：{{visit.registerId||'—'}}</text></view><view class="card-body"><view class="department-icon"><ServiceIcon type="heart" tone="blue" size="large"/></view><view class="medical-info"><text class="department">{{visit.department}}</text><text class="doctor">{{visit.doctor}}</text><text v-if="visit.location" class="location">⌖ {{visit.location}}</text></view><view class="time-info"><text class="date">{{visit.date}}</text><text>{{visit.time}}</text></view></view><view class="card-foot"><view><text>就诊人：{{visit.patient||'患者'}}</text><text v-if="visit.previsitState==='completed'" class="finished">✓ 预问诊已完成</text></view><view class="actions"><button v-if="visit.previsitState==='none'" class="previsit" size="mini" @tap="$emit('previsit')">AI预问诊</button><button v-else-if="visit.previsitState==='in_progress'" class="continue" size="mini" @tap="$emit('previsit')">继续预问诊</button><button v-else-if="visit.previsitState==='completed'" class="viewed" size="mini" @tap="$emit('previsit')">查看总结</button><button size="mini" @tap="$emit('action')">{{visit.status.includes('待缴')?'去缴费':'查看详情'}}</button></view></view></view></template>
